import { eq as eq35, and as and27, desc as desc20, sql as sql25 } from "drizzle-orm";
var GovernanceService = class {
  /**
   * Get DAO proposals from database
   */
  async getProposals(daoId, status, limit = 50, offset = 0) {
    const where = status ? and27(eq35(proposals.daoId, daoId), eq35(proposals.status, status)) : eq35(proposals.daoId, daoId);
    const proposalQuery = db.select().from(proposals).where(where).orderBy(desc20(proposals.createdAt)).limit(limit).offset(offset);
    const proposalsList = await proposalQuery;
    const totalQuery = await db.select({ count: sql25`count(*)` }).from(proposals).where(where);
    const total = Number(totalQuery[0]?.count || 0);
    return {
      proposals: proposalsList,
      total
    };
  }
  /**
   * Get proposal by ID with vote counts
   */
  async getProposalById(proposalId) {
    const proposalData = await db.select().from(proposals).where(eq35(proposals.id, proposalId)).limit(1);
    if (proposalData.length === 0) {
      throw new Error(`Proposal ${proposalId} not found`);
    }
    const proposal = proposalData[0];
    const voteCounts = await db.select({
      votesFor: sql25`SUM(CASE WHEN ${votes.voteType} = 'for' THEN 1 ELSE 0 END)`,
      votesAgainst: sql25`SUM(CASE WHEN ${votes.voteType} = 'against' THEN 1 ELSE 0 END)`,
      votesAbstain: sql25`SUM(CASE WHEN ${votes.voteType} = 'abstain' THEN 1 ELSE 0 END)`,
      totalVotes: sql25`COUNT(*)`
    }).from(votes).where(eq35(votes.proposalId, proposalId));
    return {
      ...proposal,
      votesFor: Number(voteCounts[0]?.votesFor || 0),
      votesAgainst: Number(voteCounts[0]?.votesAgainst || 0),
      votesAbstain: Number(voteCounts[0]?.votesAbstain || 0),
      totalVotes: Number(voteCounts[0]?.totalVotes || 0)
    };
  }
  /**
   * Get user's voting power
   */
  async getVotingPower(userId, daoId) {
    const contributions6 = await db.select({ count: sql25`count(*)` }).from(userActivities2).where(and27(
      eq35(userActivities2.userId, userId),
      eq35(userActivities2.dao_id, daoId),
      eq35(userActivities2.type, "contribution")
    ));
    const basePower = Number(contributions6[0]?.count || 0) * 10;
    const delegatedIn = await db.select({ count: sql25`count(*)` }).from(voteDelegations).where(and27(
      eq35(voteDelegations.daoId, daoId),
      eq35(voteDelegations.delegateId, userId)
    ));
    const delegated = Number(delegatedIn[0]?.count || 0);
    const delegatedOut = await db.select({ count: sql25`count(*)` }).from(voteDelegations).where(and27(
      eq35(voteDelegations.daoId, daoId),
      eq35(voteDelegations.delegatorId, userId)
    ));
    const delegatedAway = Number(delegatedOut[0]?.count || 0);
    const total = basePower + delegated - delegatedAway;
    return {
      power: basePower,
      delegated: delegated - delegatedAway,
      total
    };
  }
};

