// server/routes/contribution-indexer.ts
import express25 from "express";

// server/services/contributionIndexerService.ts
init_db();
init_schema2();
init_logger();
init_tokenService();
import { ethers as ethers3 } from "ethers";
import { eq as eq43, and as and33, sql as sql30 } from "drizzle-orm";
var logger14 = Logger.getLogger();
var ContributionIndexerService = class {
  constructor() {
    this.isRunning = false;
    this.lastProcessedBlock = {};
    this.pendingContributions = [];
  }
  async start() {
    if (this.isRunning) return;
    this.isRunning = true;
    logger14.info("\u{1F50D} Starting Contribution Indexer Service");
    setInterval(() => this.indexContributions(), 3e4);
    await this.indexContributions();
  }
  async indexContributions() {
    try {
      const activeDaos = await db.select({
        id: daos2.id,
        name: daos2.name,
        treasuryAddress: sql30`(
            SELECT address FROM ${wallets} 
            WHERE dao_id = ${daos2.id} 
            AND wallet_type = 'dao' 
            LIMIT 1
          )`.as("treasury_address")
      }).from(daos2).where(eq43(daos2.isArchived, false));
      for (const dao of activeDaos) {
        if (!dao.treasuryAddress) continue;
        await this.indexDaoContributions(
          dao.id,
          dao.treasuryAddress,
          dao.name
        );
      }
    } catch (error) {
      logger14.error("Error indexing contributions:", error);
    }
  }
  async indexDaoContributions(daoId, treasuryAddress, daoName) {
    try {
      const provider2 = tokenService.provider;
      const currentBlock = await provider2.getBlockNumber();
      const fromBlock = this.lastProcessedBlock[daoId] || currentBlock - 1e3;
      const toBlock = currentBlock;
      const transfers = await this.getTransfersToAddress(
        treasuryAddress,
        fromBlock,
        toBlock
      );
      logger14.info(`Found ${transfers.length} transfers to DAO ${daoName}`);
      for (const transfer of transfers) {
        await this.processTransfer(daoId, transfer);
      }
      this.lastProcessedBlock[daoId] = currentBlock;
    } catch (error) {
      logger14.error(`Error indexing DAO ${daoId}:`, error);
    }
  }
  async getTransfersToAddress(toAddress, fromBlock, toBlock) {
    const provider2 = tokenService.provider;
    const transfers = [];
    try {
      const nativeTransfers = await this.getNativeTransfers(
        toAddress,
        fromBlock,
        toBlock
      );
      transfers.push(...nativeTransfers);
      const erc20Transfers = await this.getERC20Transfers(
        toAddress,
        fromBlock,
        toBlock
      );
      transfers.push(...erc20Transfers);
    } catch (error) {
      logger14.error("Error fetching transfers:", error);
    }
    return transfers;
  }
  async getNativeTransfers(toAddress, fromBlock, toBlock) {
    const provider2 = tokenService.provider;
    const transfers = [];
    for (let i = fromBlock; i <= toBlock; i++) {
      try {
        const block = await provider2.getBlock(i, true);
        if (!block || !block.transactions) continue;
        for (const tx of block.transactions) {
          if (typeof tx === "string") continue;
          if (tx.to?.toLowerCase() === toAddress.toLowerCase() && tx.value > 0n) {
            transfers.push({
              from: tx.from,
              to: tx.to,
              value: tx.value.toString(),
              currency: "CELO",
              hash: tx.hash,
              blockNumber: i,
              timestamp: new Date(block.timestamp * 1e3)
            });
          }
        }
      } catch (error) {
        continue;
      }
    }
    return transfers;
  }
  async getERC20Transfers(toAddress, fromBlock, toBlock) {
    const transfers = [];
    const provider2 = tokenService.provider;
    const transferTopic = ethers3.id("Transfer(address,address,uint256)");
    const supportedTokens = [
      { symbol: "cUSD", address: process.env.CUSD_ADDRESS },
      { symbol: "cEUR", address: process.env.CEUR_ADDRESS },
      { symbol: "USDT", address: process.env.USDT_ADDRESS }
    ].filter((t) => t.address);
    for (const token of supportedTokens) {
      try {
        const filter = {
          address: token.address,
          topics: [
            transferTopic,
            null,
            // from (any)
            ethers3.zeroPadValue(toAddress, 32)
            // to (our DAO)
          ],
          fromBlock,
          toBlock
        };
        const logs2 = await provider2.getLogs(filter);
        for (const log of logs2) {
          const iface = new ethers3.Interface([
            "event Transfer(address indexed from, address indexed to, uint256 value)"
          ]);
          const parsed = iface.parseLog(log);
          if (parsed) {
            const block = await provider2.getBlock(log.blockNumber);
            transfers.push({
              from: parsed.args.from,
              to: parsed.args.to,
              value: parsed.args.value.toString(),
              currency: token.symbol,
              hash: log.transactionHash,
              blockNumber: log.blockNumber,
              timestamp: new Date((block?.timestamp || 0) * 1e3)
            });
          }
        }
      } catch (error) {
        logger14.error(`Error fetching ${token.symbol} transfers:`, error);
      }
    }
    return transfers;
  }
  async processTransfer(daoId, transfer) {
    try {
      const existing = await db.select().from(contributions2).where(eq43(contributions2.transactionHash, transfer.hash)).limit(1);
      if (existing.length > 0) {
        return;
      }
      const userWallet = await db.select({ userId: wallets.userId }).from(wallets).where(
        and33(
          sql30`LOWER(${wallets.address}) = LOWER(${transfer.from})`,
          eq43(wallets.isActive, true)
        )
      ).limit(1);
      const amountInEther = ethers3.formatUnits(transfer.value, 18);
      if (userWallet.length > 0) {
        await db.insert(contributions2).values({
          userId: userWallet[0].userId,
          daoId,
          amount: amountInEther,
          currency: transfer.currency,
          transactionHash: transfer.hash,
          purpose: "general",
          isAnonymous: false,
          createdAt: transfer.timestamp,
          vault: false
        });
        logger14.info(`\u2705 Auto-recorded contribution: ${amountInEther} ${transfer.currency} from known wallet`);
      } else {
        const pending = {
          id: transfer.hash,
          daoId,
          fromAddress: transfer.from,
          amount: amountInEther,
          currency: transfer.currency,
          transactionHash: transfer.hash,
          blockNumber: transfer.blockNumber,
          timestamp: transfer.timestamp,
          claimed: false
        };
        this.pendingContributions.push(pending);
        logger14.info(`\u23F3 Pending contribution: ${amountInEther} ${transfer.currency} from unknown wallet ${transfer.from.slice(0, 10)}...`);
      }
    } catch (error) {
      logger14.error("Error processing transfer:", error);
    }
  }
  async getPendingContributions(daoId) {
    if (daoId) {
      return this.pendingContributions.filter(
        (p) => p.daoId === daoId && !p.claimed
      );
    }
    return this.pendingContributions.filter((p) => !p.claimed);
  }
  async claimContribution(userId, transactionHash, walletAddress) {
    try {
      const pending = this.pendingContributions.find(
        (p) => p.transactionHash === transactionHash && !p.claimed
      );
      if (!pending) {
        throw new Error("Pending contribution not found");
      }
      const existingWallet = await db.select().from(wallets).where(
        and33(
          sql30`LOWER(${wallets.address}) = LOWER(${walletAddress})`,
          eq43(wallets.userId, userId)
        )
      ).limit(1);
      if (existingWallet.length === 0) {
        await db.insert(wallets).values({
          userId,
          address: walletAddress,
          currency: pending.currency,
          walletType: "personal",
          isActive: true
        });
      }
      await db.insert(contributions2).values({
        userId,
        daoId: pending.daoId,
        amount: pending.amount,
        currency: pending.currency,
        transactionHash: pending.transactionHash,
        purpose: "general",
        isAnonymous: false,
        createdAt: pending.timestamp,
        vault: false
      });
      pending.claimed = true;
      logger14.info(`\u2705 User ${userId} claimed contribution: ${pending.amount} ${pending.currency}`);
      return true;
    } catch (error) {
      logger14.error("Error claiming contribution:", error);
      return false;
    }
  }
};
var contributionIndexer = new ContributionIndexerService();

