var requireRole3 = (...allowedRoles) => {
  return async (req, res, next) => {
    try {
      const userId = req.user?.userId || req.user?.claims?.sub;
      if (!userId) {
        return res.status(401).json({
          success: false,
          error: { message: "Authentication required" }
        });
      }
      const userResult = await db.select({ role: users.roles }).from(users).where(eq46(users.id, userId)).limit(1);
      if (userResult.length === 0) {
        return res.status(404).json({
          success: false,
          error: { message: "User not found" }
        });
      }
      const userRoleRaw = userResult[0].role;
      const userRole = userRoleRaw === null ? "user" : userRoleRaw;
      req.userRole = userRole;
      if (!allowedRoles.includes(userRole)) {
        logger15.warn("Access denied - insufficient role", {
          userId,
          userRole,
          requiredRoles: allowedRoles
        });
        return res.status(403).json({
          success: false,
          error: { message: "Insufficient permissions" }
        });
      }
      if (!ROLE_PERMISSIONS[userRole]) {
        logger15.warn("Undefined global role, falling back to user", { userId, userRole });
      }
      req.userPermissions = ROLE_PERMISSIONS[userRole] || ROLE_PERMISSIONS.user;
      next();
    } catch (error) {
      logger15.error("Role check failed", error);
      next(new AppError("Authorization check failed", 500));
    }
  };
};

// server/routes/admin.ts
init_config();
import os from "os";
import bcrypt3 from "bcryptjs";
import jwt3 from "jsonwebtoken";
var router33 = Router11();
var requireSuperAdmin = requireRole3("super_admin");
function isUser(obj) {
  return obj && typeof obj.id === "string" && typeof obj.email === "string" && typeof obj.password === "string" && typeof obj.roles === "string";
}
router33.post("/auth/admin-login", async (req, res) => {
  const { email, password } = req.body;
  if (!email || !password) {
    return res.status(400).json({ message: "Email and password required" });
  }
  try {
    const userArr = await db.select().from(users).where(eq47(users.email, email)).limit(1);
    const user = userArr[0];
    if (!isUser(user)) {
      return res.status(401).json({ message: "Invalid credentials or not an admin/superuser" });
    }
    const hasAdminAccess = user.roles === "superUser" || user.roles === "admin" || user.isSuperUser === true;
    if (!hasAdminAccess) {
      return res.status(401).json({ message: "Invalid credentials or not an admin/superuser" });
    }
    if (!user.password) {
      return res.status(401).json({ message: "No password set for this user" });
    }
    const valid = await bcrypt3.compare(password, user.password);
    if (!valid) {
      return res.status(401).json({ message: "Invalid credentials" });
    }
    const token = jwt3.sign({ id: user.id, role: user.roles }, process.env.JWT_SECRET || "changeme", { expiresIn: "1d" });
    const responseUser = {
      id: user.id,
      email: user.email,
      firstName: user.firstName || "",
      lastName: user.lastName || "",
      phone: user.phone || null,
      role: user.roles,
      isSuperUser: user.roles === "superUser" || user.isSuperUser === true,
      isAdmin: user.roles === "admin" || user.roles === "superUser" || user.isSuperUser === true,
      walletAddress: user.walletAddress || null,
      isEmailVerified: user.emailVerified || false,
      isPhoneVerified: user.phoneVerified || false,
      profilePicture: user.profileImageUrl || null
    };
    res.json({
      success: true,
      data: {
        user: responseUser,
        accessToken: token
      }
    });
  } catch (err) {
    logger.error("Admin login error:", err);
    res.status(500).json({ message: "Server error" });
  }
});
router33.post("/auth/superuser-register", async (req, res) => {
  const { email, password, firstName, lastName, name } = req.body;
  if (!email || !password) {
    return res.status(400).json({ message: "Email and password required" });
  }
  try {
    const existingArr = await db.select().from(users).where(eq47(users.email, email)).limit(1);
    if (existingArr[0]) {
      return res.status(409).json({ message: "Email already registered" });
    }
    const hash = await bcrypt3.hash(password, 10);
    const [newUser] = await db.insert(users).values({
      id: crypto.randomUUID(),
      email,
      password: hash,
      name: name || firstName || "",
      firstName: firstName || "",
      lastName: lastName || "",
      roles: "superUser",
      isSuperUser: true,
      isEmailVerified: true,
      createdAt: /* @__PURE__ */ new Date()
    }).returning();
    if (!newUser) {
      return res.status(500).json({ message: "User creation failed" });
    }
    const responseUser = {
      id: newUser.id,
      email: newUser.email,
      firstName: newUser.firstName || "",
      lastName: newUser.lastName || "",
      role: newUser.roles,
      roles: newUser.roles,
      isSuperUser: newUser.isSuperUser === true,
      isAdmin: newUser.roles === "superUser" || newUser.roles === "admin"
    };
    const token = jwt3.sign({ id: newUser.id, role: newUser.roles, isSuperUser: newUser.isSuperUser }, process.env.JWT_SECRET || "changeme", { expiresIn: "1d" });
    res.json({ success: true, data: { user: responseUser, accessToken: token } });
  } catch (err) {
    logger.error("Superuser register error:", err);
    res.status(500).json({ message: "Server error" });
  }
});
