  monthlyWithdrawalVolume: decimal9("monthly_withdrawal_volume", { precision: 20, scale: 2 }).default("0"),
  monthlyP2pSentVolume: decimal9("monthly_p2p_sent_volume", { precision: 20, scale: 2 }).default("0"),
