async function initializeUserAccounts() {
  console.log("\u{1F680} Starting user accounts initialization...");
  try {
    const usersWithoutAccounts = await db.execute(
      sql40`
        SELECT u.id 
        FROM users u
        LEFT JOIN accounts a ON u.id = a.user_id
        WHERE a.id IS NULL
        GROUP BY u.id
      `
    );
    console.log(`\u{1F4CA} Found ${usersWithoutAccounts.rows.length} users without accounts`);
    if (usersWithoutAccounts.rows.length === 0) {
      console.log("\u2705 All users already have accounts initialized");
      return;
    }
    let createdCount = 0;
    for (const row of usersWithoutAccounts.rows) {
      const userId = row.id;
      for (const accountType of ACCOUNT_TYPES2) {
        try {
          await db.insert(accounts).values({
            userId,
            accountType,
            balance: "0",
            currency: CURRENCY,
            status: "active",
            locked: "0"
          });
          createdCount++;
        } catch (error) {
          console.error(`\u274C Error creating ${accountType} account for user ${userId}:`, error);
        }
      }
    }
    console.log(`\u2705 Successfully created ${createdCount} accounts`);
    console.log(`\u{1F4C8} Initialized ${createdCount / ACCOUNT_TYPES2.length} users with multi-account structure`);
  } catch (error) {
    console.error("\u274C Error during account initialization:", error);
    throw error;
  }
}
async function getAccountInitializationSummary() {
  try {
    const userCount = await db.execute(
      sql40`SELECT COUNT(DISTINCT user_id) as total FROM accounts`
    );
    const accountStats = await db.execute(
      sql40`
        SELECT account_type, COUNT(*) as count 
        FROM accounts 
        GROUP BY account_type
        ORDER BY account_type
      `
    );
    return {
      usersWithAccounts: userCount.rows[0]?.total || 0,
      accountsByType: accountStats.rows
    };
  } catch (error) {
    console.error("Error getting account summary:", error);
    throw error;
  }
}
