import { Router as Router17 } from "express";
import { eq as eq62, desc as desc33, and as and48, like as like3, inArray as inArray5 } from "drizzle-orm";
import multer from "multer";
import path2 from "path";
import fs2 from "fs";
var router42 = Router17();
var storage2 = multer.diskStorage({
  destination: (req, file, cb) => {
    const uploadDir = "uploads/";
    if (!fs2.existsSync(uploadDir)) {
      fs2.mkdirSync(uploadDir, { recursive: true });
    }
    cb(null, uploadDir);
  },
  filename: (req, file, cb) => {
    const uniqueSuffix = Date.now() + "-" + Math.round(Math.random() * 1e9);
    const sanitizedName = file.originalname.replace(/[^a-zA-Z0-9.-]/g, "_");
    cb(null, file.fieldname + "-" + uniqueSuffix + path2.extname(sanitizedName));
  }
});
var fileFilter = (req, file, cb) => {
  const allowedMimes = {
    "image/jpeg": [".jpg", ".jpeg"],
    "image/png": [".png"],
    "image/gif": [".gif"],
    "image/webp": [".webp"],
    "application/pdf": [".pdf"],
    "application/msword": [".doc"],
    "application/vnd.openxmlformats-officedocument.wordprocessingml.document": [".docx"],
    "application/vnd.ms-excel": [".xls"],
    "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet": [".xlsx"],
    "text/plain": [".txt"],
    "text/csv": [".csv"]
  };
  const ext = path2.extname(file.originalname).toLowerCase();
  const mimeType = file.mimetype.toLowerCase();
  const isAllowedMime = mimeType in allowedMimes;
  const isValidExt = isAllowedMime && allowedMimes[mimeType].includes(ext);
  if (!isAllowedMime || !isValidExt) {
    return cb(new Error(`Invalid file type. Allowed types: ${Object.keys(allowedMimes).join(", ")}`));
  }
  const dangerousExts = [".exe", ".bat", ".cmd", ".com", ".pif", ".scr", ".vbs", ".js", ".jar", ".zip", ".rar", ".7z"];
  if (dangerousExts.includes(ext.toLowerCase())) {
    return cb(new Error("Executable files are not allowed"));
  }
  cb(null, true);
};
var upload = multer({
  storage: storage2,
  fileFilter,
  limits: {
    fileSize: 10 * 1024 * 1024,
    // 10MB limit
    files: 1
    // Only allow single file upload
  }
});
