router54.get("/:id/analytics", async (req, res) => {
  try {
    const { id } = req.params;
    const vault = vaultService?.getVault(id);
    if (!vault) {
      return res.status(404).json({ success: false, error: "Vault not found" });
    }
    const performance2 = vault.performanceHistory;
    const totalReturn = (vault.totalValue - 1e6) / 1e6 * 100 || 0;
    const avgDailyReturn = performance2.length > 0 ? performance2.reduce((sum5, p) => sum5 + p.dailyReturn, 0) / performance2.length : 0;
    let maxDrawdown = 0;
    let peak = vault.totalValue;
    for (const p of performance2) {
      if (p.totalValue > peak) peak = p.totalValue;
      const drawdown = (peak - p.totalValue) / peak * 100;
      if (drawdown > maxDrawdown) maxDrawdown = drawdown;
    }
    const totalTrades = performance2.reduce((sum5, p) => sum5 + p.trades, 0);
    res.json({
      success: true,
      data: {
        vaultId: id,
        totalValue: vault.totalValue,
        depositorCount: vault.depositors.size,
        totalReturn,
        avgDailyReturn,
        maxDrawdown,
        totalTrades,
        positions: vault.positions,
        isActive: vault.isActive
      }
    });
  } catch (error) {
    res.status(500).json({ success: false, error: String(error) });
  }
});
