router61.get(
  "/find-symbol",
  asyncHandler2(async (req, res) => {
    const { symbol, exchanges: exchangesParam } = req.query;
    if (!symbol) {
      return res.status(400).json({ error: "symbol parameter required" });
    }
    const allExchanges = ccxtService_default.getAvailableExchanges();
    const exchangesToSearch = exchangesParam ? exchangesParam.split(",").map((e) => e.trim().toLowerCase()) : allExchanges;
    try {
      const results = await Promise.all(
        exchangesToSearch.map(async (exchange) => {
          try {
            const ticker = await ccxtService_default.getTickerFromExchange(exchange, symbol);
            if (ticker) {
              return {
                exchange,
                symbol: ticker.symbol,
                price: ticker.last,
                bid: ticker.bid,
                ask: ticker.ask,
                volume: ticker.volume,
                timestamp: ticker.timestamp
              };
            }
            return null;
          } catch (error) {
            return null;
          }
        })
      );
      const found = results.filter((r) => r !== null);
      res.json({
        symbol,
        found: found.length,
        exchanges: found,
        timestamp: Date.now()
      });
    } catch (error) {
      logger.error(`Find symbol failed: ${error.message}`);
      res.status(500).json({
        error: "Failed to search for symbol",
        details: error.message
      });
    }
  })
);
router61.post(
  "/order/validate",
  asyncHandler2(async (req, res) => {
    const { exchange, symbol, side, amount, price } = req.body;
    if (!exchange || !symbol || !side || !amount) {
      return res.status(400).json({
        error: "Missing required fields: exchange, symbol, side, amount"
      });
    }
    if (!["buy", "sell"].includes(side)) {
      return res.status(400).json({ error: 'Invalid side. Must be "buy" or "sell"' });
    }
    if (typeof amount !== "number" || amount <= 0) {
      return res.status(400).json({ error: "Amount must be a positive number" });
    }
    try {
      const validation = await ccxtService_default.validateOrder(exchange, symbol, side, amount, price);
      res.json({
        valid: validation.valid,
        errors: validation.errors,
        market: validation.market ? {
          symbol: validation.market.symbol,
          base: validation.market.base,
          quote: validation.market.quote,
          maker_fee: validation.market.maker,
          taker_fee: validation.market.taker,
          limits: validation.market.limits
        } : null
      });
    } catch (error) {
      logger.error(`Order validation failed: ${error.message}`);
      res.status(500).json({
        error: "Failed to validate order",
        details: error.message
      });
    }
  })
);
