function getDailyLimitByType(daoType) {
  switch (daoType) {
    case "short_term":
      return "5000.00";
    // $5K daily for chama
    case "collective":
      return "10000.00";
    // $10K daily for collective
    default:
      return "1000.00";
  }
}
function getMonthlyBudgetByType(daoType) {
  switch (daoType) {
    case "short_term":
      return "50000.00";
    // $50K monthly for chama
    case "collective":
      return "100000.00";
    // $100K monthly for collective
    default:
      return "10000.00";
  }
}
function calculateNextRotation(from, frequency) {
  const next = new Date(from);
  switch (frequency) {
    case "weekly":
      next.setDate(next.getDate() + 7);
      break;
    case "monthly":
      next.setMonth(next.getMonth() + 1);
      break;
    case "quarterly":
      next.setMonth(next.getMonth() + 3);
      break;
  }
  return next;
}
function getMultisigConfigForDaoType(type) {
  if (type === "free") {
    return {
      enabled: false,
      // Single-sig for free tier
      requiredSignatures: 1,
      withdrawalThreshold: 500,
      // $500 threshold
      dailyLimit: 1e3
      // $1K/day
    };
  } else if (type === "collective") {
    return {
      enabled: true,
      // 3-of-5 multi-sig
      requiredSignatures: 3,
      withdrawalThreshold: 1e3,
      // $1K threshold
      dailyLimit: 5e3
      // $5K/day
    };
  } else {
    return {
      enabled: true,
      // 5-of-7 multi-sig
      requiredSignatures: 5,
      withdrawalThreshold: 5e3,
      // $5K threshold
      dailyLimit: 1e4
      // $10K/day
    };
  }
}

// server/api/payments_estimate_gas.ts
init_tokenService();
init_tokenRegistry();
async function paymentsEstimateGasHandler(req, res) {
  try {
    const { tokenSymbol, toAddress, amount, operationType = "transfer" } = req.body;
    if (!tokenSymbol || !toAddress || !amount) {
      return res.status(400).json({
        error: "Missing required parameters",
        required: ["tokenSymbol", "toAddress", "amount"]
      });
    }
    const token = TokenRegistry.getToken(tokenSymbol);
    if (!token) {
      return res.status(400).json({
        error: `Unsupported token: ${tokenSymbol}`,
        supportedTokens: TokenRegistry.getSupportedTokens()
      });
    }
    if (!toAddress.match(/^0x[a-fA-F0-9]{40}$/)) {
      return res.status(400).json({
        error: "Invalid Ethereum address format"
      });
    }
    const amountNum = parseFloat(amount);
    if (isNaN(amountNum) || amountNum <= 0) {
      return res.status(400).json({
        error: "Amount must be a positive number"
      });
    }
    const defaultSender = process.env.DEFAULT_SENDER_ADDRESS || "0x000000000000000000000000000000000000dead";
    const gasEstimateStr = await tokenService.estimateTokenGas(tokenSymbol, toAddress, amount, defaultSender);
    const gasEstimate = BigInt(gasEstimateStr);
    const gasPrice = await tokenService.provider.getFeeData();
    const estimatedCostWei = gasEstimate * (gasPrice.gasPrice || BigInt(0));
    const estimatedCostCelo = __require("ethers").formatUnits(estimatedCostWei, 18);
    const operationMultipliers = {
      transfer: 1.1,
      // 10% buffer
      deposit: 1.2,
      // 20% buffer for vault operations
      withdraw: 1.3
      // 30% buffer for complex withdrawals
    };
    const safetyMultiplier = operationMultipliers[operationType];
    const safeGasEstimate = BigInt(Math.ceil(Number(gasEstimate) * safetyMultiplier));
    res.json({
      success: true,
      gasEstimate: {
        operation: operationType,
        token: {
          symbol: tokenSymbol,
          name: token.name,
          decimals: token.decimals
        },
        gas: {
          estimated: gasEstimate.toString(),
          recommended: safeGasEstimate.toString(),
          price: gasPrice.gasPrice?.toString() || "0",
          maxFee: gasPrice.maxFeePerGas?.toString() || "0",
          maxPriorityFee: gasPrice.maxPriorityFeePerGas?.toString() || "0"
        },
        cost: {
          estimatedCELO: estimatedCostCelo,
          safetyMultiplier,
          estimatedUSD: (parseFloat(estimatedCostCelo) * 0.65).toFixed(4)
          // Rough CELO price
        },
        network: "Celo",
        timestamp: (/* @__PURE__ */ new Date()).toISOString()
      }
    });
  } catch (error) {
    console.error("Gas estimation error:", error);
    res.status(500).json({
      success: false,
      error: "Failed to estimate gas",
      details: error instanceof Error ? error.message : "Unknown error",
      fallback: {
        // Provide fallback estimates for common operations
        transferGas: "21000",
        erc20TransferGas: "65000",
        vaultDepositGas: "150000",
        vaultWithdrawGas: "200000"
      }
    });
  }
}

// server/api/payments_index.ts
init_db();
init_schema2();
init_logger();
import { eq as eq85, and as and60, desc as desc42 } from "drizzle-orm";
var logger20 = Logger.getLogger();
async function paymentsIndexHandler(req, res) {
  try {
    const session = req.session;
    if (!session?.user?.id) {
      return res.status(401).json({
        error: "Unauthorized",
        message: "You must be logged in to view payments"
      });
    }
    const userId = session.user.id;
    const {
      status = "all",
      // all, pending, completed, failed
      type = "all",
      // all, sent, received
      startDate,
      endDate,
      limit = "50",
      offset = "0"
    } = req.query;
    const conditions = [eq85(walletTransactions2.toUserId, userId)];
    if (status && status !== "all") {
      conditions.push(eq85(walletTransactions2.status, status));
    }
    if (type && type !== "all") {
      conditions.push(eq85(walletTransactions2.type, type));
    }
    if (startDate) {
      const start = new Date(startDate);
      conditions.push(eq85(walletTransactions2.createdAt, start));
    }
    if (endDate) {
      const end = new Date(endDate);
      conditions.push(eq85(walletTransactions2.createdAt, end));
    }
    const totalResult = await db.select({ count: walletTransactions2.id }).from(walletTransactions2).where(and60(...conditions));
    const total = totalResult.length;
    const payments2 = await db.select().from(walletTransactions2).where(and60(...conditions)).orderBy(desc42(walletTransactions2.createdAt)).limit(parseInt(limit)).offset(parseInt(offset));
    const enrichedPayments = await Promise.all(
      payments2.map(async (payment) => {
        let recipientDetails = null;
        if (payment.toUserId) {
          const recipient = await db.query.users.findFirst({
            where: eq85(users.id, payment.toUserId),
            columns: {
              id: true,
              name: true,
              email: true,
              walletAddress: true
            }
          });
          recipientDetails = recipient;
        }
        return {
          ...payment,
          recipientDetails,
          metadata: typeof payment.metadata === "string" ? JSON.parse(payment.metadata) : payment.metadata
        };
      })
    );
    return res.status(200).json({
      success: true,
      data: {
        payments: enrichedPayments,
        pagination: {
          total,
          limit: parseInt(limit),
          offset: parseInt(offset),
          hasMore: parseInt(offset) + parseInt(limit) < total
        },
        filters: {
          status,
          type,
          startDate,
          endDate
        }
      }
    });
  } catch (error) {
    const errorMsg = error instanceof Error ? error.message : String(error);
    logger20.error(`Error fetching payments: ${errorMsg}`, error);
    return res.status(500).json({
      success: false,
      error: "Failed to fetch payments",
      message: errorMsg
    });
  }
}

