async function authorizeVaultAccess(req, res, next) {
  try {
    const userId = req.user?.claims?.id;
    const { vaultId } = req.params;
    if (!userId) {
      return res.status(401).json({ error: "Authentication required" });
    }
    if (!vaultId) {
      return res.status(400).json({ error: "Vault ID is required" });
    }
    const vault = await vaultService2.getVaultById(vaultId);
    if (!vault) {
      return res.status(404).json({ error: "Vault not found" });
    }
    if (vault.userId !== userId && !await vaultService2.hasVaultAccess(userId, vaultId)) {
      return res.status(403).json({ error: "Access denied to this vault" });
    }
    req.vault = vault;
    next();
  } catch (error) {
    logger25.error("Vault authorization error:", error);
    res.status(500).json({ error: "Authorization check failed" });
  }
}

