// server/vite.ts
import { nanoid } from "nanoid";
var __dirname3 = dirname2(fileURLToPath4(import.meta.url));
var viteLogger = createLogger2();
async function setupVite(app2, server2) {
  const vite = await createViteServer({
    ...vite_config_default,
    configFile: false,
    customLogger: {
      ...viteLogger,
      error: (msg, options) => {
        viteLogger.error(msg, options);
        process.exit(1);
      }
    },
    server: {
      middlewareMode: true,
      hmr: {
        server: server2
      }
    },
    appType: "custom"
  });
  app2.use(vite.middlewares);
  app2.use("*", async (req, res, next) => {
    const url = req.originalUrl;
    try {
      const clientTemplate = path4.resolve(__dirname3, "../client/index.html");
      let template = await fs3.promises.readFile(clientTemplate, "utf-8");
      template = template.replace(
        `src="/src/main.tsx"`,
        `src="/src/main.tsx?v=${nanoid()}"`
      );
      const html = await vite.transformIndexHtml(url, template);
      res.status(200).set({ "Content-Type": "text/html" }).end(html);
    } catch (e) {
      vite.ssrFixStacktrace(e);
      next(e);
    }
  });
}
function serveStatic(app2) {
  const distPath = path4.resolve(__dirname3, "../../dist/public");
  if (!fs3.existsSync(distPath)) {
    throw new Error(
      `\u274C Could not find the build directory: ${distPath}, make sure to run 'npm run build' first`
    );
  }
  app2.use(express37.static(distPath, {
    maxAge: "1y",
    // Cache assets for 1 year
    immutable: true,
    // Assets are immutable (have hash in filename)
    etag: true,
    // Enable ETag for conditional requests
    lastModified: true,
    setHeaders: (res, path6) => {
      if (path6.endsWith(".html")) {
        res.setHeader("Cache-Control", "public, max-age=300");
      }
    }
  }));
  app2.use("*", (_req, res) => {
    res.setHeader("Cache-Control", "no-cache");
    res.sendFile(path4.join(distPath, "index.html"));
  });
}

