// server/middleware/operational-audit.ts
init_logger2();
function auditLoggerCaptureRequest(req, res, next) {
  req.auditStartTime = Date.now();
  if (req.body && ["POST", "PUT", "PATCH"].includes(req.method)) {
    const auditBody = { ...req.body };
    if (auditBody.password) auditBody.password = "[REDACTED]";
    if (auditBody.secret) auditBody.secret = "[REDACTED]";
    if (auditBody.apiKey) auditBody.apiKey = "[REDACTED]";
    if (auditBody.token) auditBody.token = "[REDACTED]";
    req.auditRequestBody = auditBody;
  }
  const originalJson = res.json.bind(res);
  res.json = function(body) {
    req.auditResponseBody = body;
    return originalJson(body);
  };
  next();
}
async function auditLoggerRecordResponse(req, res, next) {
  try {
    const auditLogger = getAuditLogger();
    const shouldLog = req.path.includes("/api/admin/") || req.method !== "GET" || // Log all write operations
    req.query.audit === "true";
    if (!shouldLog) {
      return next();
    }
    const duration = req.auditStartTime ? Date.now() - req.auditStartTime : 0;
    const actor = req.user?.id || req.ip || "unknown";
    const statusCode = res.statusCode;
    let actionDescription = `${req.method} ${req.path}`;
    if (req.path.includes("/admin/")) {
      if (req.method === "GET") actionDescription = `ADMIN_GET: ${req.path}`;
      if (req.method === "POST") actionDescription = `ADMIN_CREATE: ${req.path}`;
      if (req.method === "PUT") actionDescription = `ADMIN_UPDATE: ${req.path}`;
      if (req.method === "DELETE") actionDescription = `ADMIN_DELETE: ${req.path}`;
    }
    if (statusCode < 400) {
      await auditLogger.logEvent(
        "config_changed",
        // Using existing action type (could extend)
        actor,
        void 0,
        // targetService
        req.path,
        // targetResource
        req.auditRequestBody,
        // previousState (input)
        req.auditResponseBody,
        // newState (output)
        actionDescription,
        {
          method: req.method,
          path: req.path,
          statusCode,
          duration,
          remoteAddr: req.ip
        }
      );
    } else {
      await auditLogger.logEvent(
        "config_changed",
        actor,
        void 0,
        req.path,
        req.auditRequestBody,
        { error: req.auditResponseBody?.error || "Unknown error", statusCode },
        `${actionDescription} - FAILED`,
        {
          method: req.method,
          path: req.path,
          statusCode,
          duration,
          remoteAddr: req.ip
        }
      );
    }
    next();
  } catch (error) {
    console.error("[AuditLogger] Error recording response:", error);
    next();
  }
}
function setupOperationalAuditLogging(app2) {
  app2.use(auditLoggerCaptureRequest);
  app2.use(auditLoggerRecordResponse);
}

