async function executeMonitoredJob(jobName, jobFn) {
  const metrics = JobMonitoringService.startJobTracking(jobName);
  try {
    const result = await jobFn();
    const recordsProcessed = typeof result === "number" ? result : void 0;
    JobMonitoringService.completeJob(metrics, recordsProcessed);
  } catch (error) {
    JobMonitoringService.failJob(metrics, error);
  }
}

